previewCss:
.darma-loader-uiverse-ruby-compass-sweep {
  position: relative;
  border: 24px solid;
  border-color: red  transparent red transparent;
  animation: darma-loader-uiverse-ruby-compass-sweep-rotate_000 2s linear infinite;
}

.darma-loader-uiverse-ruby-compass-sweep:before,
.darma-loader-uiverse-ruby-compass-sweep:after {
content: "";
display: block;
border: 24px solid transparent;
border-left-color: red;
position: absolute;
left: -24px;
top: -24px;
animation: darma-loader-uiverse-ruby-compass-sweep-prix 1s infinite ease-in;
transform-origin: 0% 100%;
}

.darma-loader-uiverse-ruby-compass-sweep:before {
border-color: transparent red transparent transparent;
transform-origin: 100% 0%;
animation-delay: 0.5s;
}

@keyframes darma-loader-uiverse-ruby-compass-sweep-rotate_000 {
100% {
transform: rotate(360deg)
}
}

@keyframes darma-loader-uiverse-ruby-compass-sweep-prix {
20% , 80% {
transform: rotate(0)
}

50% {
transform: rotate(-90deg)
}
}

